# Anthropic SDK, single-item classifier from anthropic import Anthropic
VERDICT_TOOL = { "name": "verdict", "description": "Report whether the input meets the criterion.", "input_schema": { "type": "object", "properties": {"sufficient": {"type": "boolean"}}, "required": ["sufficient"], "additionalProperties": False, }, }
client = Anthropic() resp = client.messages.create( model="claude-sonnet-4-6", max_tokens=64, system=SYSTEM_PROMPT, tools=[VERDICT_TOOL], tool_choice={"type": "tool", "name": "verdict"}, messages=[{"role": "user", "content": item_text}], ) verdict = next( b.input["sufficient"] for b in resp.content if b.type == "tool_use" )

# Claude Agent SDK — minimum-context classifier from claude_agent_sdk import ( ClaudeAgentOptions, query, tool, create_sdk_mcp_server, AssistantMessage, ToolUseBlock, )
@tool("verdict", "Yes/no on the input", {"type": "object", "properties": {"sufficient": {"type": "boolean"}}, "required": ["sufficient"]}) async def verdict_tool(args): return {"content": [{"type": "text", "text": "ok"}]}
server = create_sdk_mcp_server(name="audit", version="0.1.0", tools=[verdict_tool])
options = ClaudeAgentOptions( model="claude-sonnet-4-6", system_prompt=SYSTEM_PROMPT, # str → replaces preset setting_sources=[], # no CLAUDE.md / AGENTS.md mcp_servers={"audit": server}, allowed_tools=["mcp__audit__verdict"], disallowed_tools=["ToolSearch"], # skip deferred-schema turn permission_mode="bypassPermissions", max_turns=2, )

# Batch prompt body
prompt = "\n\n".join(f'<doc n="{i+1}">\n{body}\n</doc>'
                     for i, body in enumerate(batch_bodies))

# Batch tool schema
TOOL = {
    "name": "verdicts",
    "description": "Sufficiency for each numbered document.",
    "input_schema": {
        "type": "object",
        "properties": {
            "results": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "n":          {"type": "integer"},
                        "sufficient": {"type": "boolean"},
                    },
                    "required": ["n", "sufficient"],
                    "additionalProperties": False,
                },
            },
        },
        "required": ["results"],
    },
}

# Build retry list from per-shard reports
import json
from pathlib import Path

failed = sorted({
    err["path"]
    for shard in Path("reports").glob("shard-*.json")
    for err in json.loads(shard.read_text())["errors"]
})
Path("retry-paths.txt").write_text("\n".join(failed) + "\n")

# Then re-run the same script with --paths-file retry-paths.txt --batch-size 3
